def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        bin_capacity = bins[i]
        if bin_capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_capacity
        if ratio > 2:
            priorities[i] = ratio ** 4 + np.log1p(ratio)
        elif ratio == 2:
            priorities[i] = 1.0
        elif 1 < ratio < 2:
            score = 0
            for j in range(1, 7):
                score += ((ratio - 1) ** j) / (j * 2)
            if bin_capacity % 2 == 0:
                score *= 2
            priorities[i] = score
        elif ratio == 1:
            priorities[i] = 0
        else:
            score = 0
            for j in range(1, 6):
                if j % 2 == 0:
                    score -= ((1 - ratio) ** j) / j
                else:
                    score += ((1 - ratio) ** j) / j
            if bin_capacity < item * 3:
                score *= 1.8
            if bin_capacity % 3 == 0:
                score += 0.5
            priorities[i] = score
    for k in range(len(priorities)):
        if priorities[k] != np.inf and priorities[k] < 0:
            priorities[k] = abs(priorities[k]) * 0.75
    return priorities
